cd /Users/kaesoon/Projects/cni-rule/05_app && cargo build --release -p cni-rules-mcp 2>&1 | tail -1
ln -sfn /Users/kaesoon/Projects/cni-rule/04_data/90_index-build/rules target/release/rules
python3 - << 'EOF'
import subprocess, json
proc = subprocess.Popen(['target/release/cni-rules-mcp'], stdin=subprocess.PIPE, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
msgs = [
  {"jsonrpc":"2.0","id":1,"method":"initialize","params":{"protocolVersion":"2025-03-26","capabilities":{},"clientInfo":{"name":"fable-smoke","version":"0.1"}}},
  {"jsonrpc":"2.0","method":"notifications/initialized"},
  {"jsonrpc":"2.0","id":2,"method":"tools/list"},
  {"jsonrpc":"2.0","id":3,"method":"tools/call","params":{"name":"search_rules","arguments":{"query":"국내 출장 일비","top_k":3}}},
]
inp = "\n".join(json.dumps(m, ensure_ascii=False) for m in msgs) + "\n"
try:
    out, err = proc.communicate(inp, timeout=90)
except subprocess.TimeoutExpired:
    proc.kill(); out, err = proc.communicate()
for line in out.strip().splitlines():
    try: d = json.loads(line)
    except Exception: continue
    if d.get('id') == 1: print('initialize:', d['result']['serverInfo'])
    elif d.get('id') == 2: print('tools:', [t['name'] for t in d['result']['tools']])
    elif d.get('id') == 3: print('search_rules:', d['result']['content'][0]['text'][:300])
if err.strip(): print('stderr:', err.strip()[:200])
EOF
